sourcesContent:
import { useState, useEffect } from "react";

const DATA = {
  name: "Amit Panda",
  title: "Embedded Systems · IoT · Automotive",
  tagline: "Engineer & Developer",
  objective: "Final-year Electronics & Computer Science Engineering student with a strong foundation in embedded systems, IoT, automotive, and software development — driven by a problem-solving mindset and a passion for building reliable, efficient solutions.",
  contact: { email: "amitpanda.18114@gmail.com", phone: "+91 8208164481", linkedin: "linkedin.com/in/Amit-Panda", location: "Palghar, Maharashtra, India" },
  education: { degree: "B.Tech – Electronics & Computer Science Engineering", college: "St John College of Engineering and Management", cgpa: "7.11 / 10.00", year: "2022 – 2026" },
  stats: [{ num: "AIR 4", label: "FKDC 2025" }, { num: "4+", label: "Projects" }, { num: "3×", label: "Award Winner" }],
  skills: [
    { title: "Languages", tags: ["Python", "C", "Embedded C", "JavaScript", "Dart"] },
    { title: "Hardware", tags: ["ESP32", "Arduino", "Raspberry Pi", "IoT Systems"] },
    { title: "Web & App", tags: ["React", "Flutter", "HTML5", "CSS", "Streamlit"] },
    { title: "AI & Vision", tags: ["OpenCV", "YOLOv5", "Machine Learning"] },
    { title: "Backend & DB", tags: ["Firebase", "MySQL", "Blynk IoT", "ThingSpeak"] },
    { title: "Tools", tags: ["Git", "GitHub", "Arduino IDE", "LaTeX"] },
  ],
  experience: [
    {
      role: "Team Captain", org: "Team Turbospace Racing", location: "Palghar, IND", period: "NOV 2025 — FEB 2026",
      points: [
        "Restructured team roles based on individual strengths and prior season performance to improve overall efficiency",
        "Reviewed the official rulebook, identified design non-compliances, and led kart modifications to meet competition standards",
        "Optimized build costs by identifying and eliminating unnecessary expenditures without compromising performance",
        "Oversaw vehicle electrical systems integration and troubleshooting during pre-race testing and competition",
        "Led failure analysis and corrective actions based on track performance and real-world testing feedback",
      ],
    },
    {
      role: "Steering Head", org: "Team Turbospace Racing", location: "Palghar, IND", period: "JULY 2025 — NOV 2025",
      points: [
        "Assembled and aligned steering rack, column, and linkages ensuring smooth operation and minimal backlash",
        "Performed inspection and adjustments based on driver feedback and track conditions",
      ],
    },
  ],
  achievements: [
    { icon: "🏆", title: "All India Rank 4 — FKDC 2025", desc: "Nationally ranked 4th for the design and development of an Electric Go-Kart." },
    { icon: "🥈", title: "All India Rank 9 — GKDC 2026", desc: "Nationally ranked 9th for the design and development of an Electric Go-Kart." },
    { icon: "🥇", title: "1st Prize — SynTech-X 2024", desc: "Winner of Project Pitching Competition for ParkEase at R.D. National College." },
    { icon: "🥇", title: "1st Prize — BIS Standards 2024", desc: "Winner of the BIS Standard Presentation Competition 2024." },
    { icon: "🎯", title: "Selected — Avishkar 2024–25", desc: "Selected in the first round of Avishkar, organized by University of Mumbai." },
  ],
  projects: [
    {
      id: "meddrip", num: "01", year: "2025–2026",
      name: "MedDrip", sub: "IoT-Based Smart IV Infusion Monitor",
      desc: "Real-time IV infusion monitoring device preventing backflow and over-infusion with Wi-Fi-based mobile alerts for medical staff.",
      tags: ["ESP32", "Embedded C", "IoT Sensors", "Wi-Fi", "Blynk IoT"],
      problem: "In hospitals and home care settings, IV infusion management is largely manual. Medical staff rely on visual checks — leading to risks of backflow and over-infusion, both of which can be life-threatening. MedDrip automates this monitoring with continuous sensor-based tracking and instant mobile alerts.",
      stats: [{ num: "Real-time", label: "Drip Rate Tracking" }, { num: "Wi-Fi", label: "Mobile Alert System" }, { num: "2-in-1", label: "Hospital + Home Use" }, { num: "ESP32", label: "Core Controller" }],
      steps: [
        { num: "01", title: "Sensor Detection", desc: "IR/weight sensors continuously monitor the IV bag fluid level and count drip rate in real time." },
        { num: "02", title: "MCU Processing", desc: "ESP32 processes sensor data, calculates flow rate, and checks against safe threshold values." },
        { num: "03", title: "Cloud Communication", desc: "Data is pushed to Blynk IoT cloud over Wi-Fi for real-time monitoring and alert triggering." },
        { num: "04", title: "Mobile Alert", desc: "When fluid drops below threshold, push notifications are sent to medical staff's phones instantly." },
      ],
      stack: [{ icon: "🔧", name: "ESP32", role: "Main Microcontroller" }, { icon: "📡", name: "Blynk IoT", role: "Cloud & Mobile Alerts" }, { icon: "⚡", name: "IR Sensor", role: "Drip Rate Detection" }, { icon: "⚖️", name: "HX711 + Load Cell", role: "Fluid Level Monitor" }, { icon: "💻", name: "Embedded C", role: "Firmware Logic" }, { icon: "🌐", name: "Wi-Fi (802.11)", role: "Connectivity" }],
      code: { lang: "Embedded C — ESP32 Drip Counter Logic", snippet: `// MedDrip - Drip Rate Monitor\n#define IR_SENSOR_PIN 4\n#define ALERT_THRESHOLD 10\n\nint dropCount = 0;\nunsigned long lastMinute = 0;\n\nvoid IRAM_ATTR onDripDetected() {\n  dropCount++;\n}\n\nvoid setup() {\n  pinMode(IR_SENSOR_PIN, INPUT_PULLUP);\n  attachInterrupt(digitalPinToInterrupt(IR_SENSOR_PIN),\n                  onDripDetected, FALLING);\n  Blynk.begin(BLYNK_AUTH, WIFI_SSID, WIFI_PASS);\n}\n\nvoid loop() {\n  Blynk.run();\n  if (millis() - lastMinute >= 60000) {\n    int dripsPerMin = dropCount;\n    dropCount = 0;\n    lastMinute = millis();\n    Blynk.virtualWrite(V1, dripsPerMin);\n    if (dripsPerMin < ALERT_THRESHOLD) {\n      Blynk.logEvent("low_drip_alert",\n        "Warning: Drip rate critically low!");\n    }\n  }\n}` },
    },
    {
      id: "medvault", num: "02", year: "2025–2026",
      name: "MedVault", sub: "AI-IoT Medicine Box for Elderly Care",
      desc: "Affordable AI-powered medicine box for India's elderly with vernacular voice reminders, refill alerts, and emergency health monitoring.",
      tags: ["AI", "IoT", "ESP32", "Firebase", "Voice Alerts", "Cloud"],
      problem: "Medication non-adherence among the elderly is a major public health challenge in India. Many elderly patients struggle with complex pill schedules and language barriers with digital devices. MedVault addresses this with an affordable, local-language voice reminder system that doesn't require smartphone literacy.",
      stats: [{ num: "6", label: "Compartments" }, { num: "Voice", label: "Vernacular Alerts" }, { num: "Cloud", label: "Remote Monitoring" }, { num: "Auto", label: "Refill Alerts" }],
      steps: [
        { num: "01", title: "Schedule Setup", desc: "Caregiver programs medication times and compartment assignments via a simple mobile interface." },
        { num: "02", title: "Voice Reminder", desc: "At scheduled times, the device plays a pre-recorded vernacular voice message for the patient." },
        { num: "03", title: "Sensor Verification", desc: "IR sensors inside each compartment detect whether the compartment was opened." },
        { num: "04", title: "Cloud Sync & Alerts", desc: "Data syncs to Firebase. Missed doses or low pills trigger instant caregiver notifications." },
      ],
      stack: [{ icon: "🔧", name: "ESP32", role: "Main Microcontroller" }, { icon: "🔥", name: "Firebase", role: "Cloud & Notifications" }, { icon: "🔊", name: "DFPlayer Mini", role: "Voice Playback" }, { icon: "👁️", name: "IR Sensors", role: "Compartment Detection" }, { icon: "💻", name: "Embedded C", role: "Firmware" }, { icon: "📱", name: "Mobile App", role: "Caregiver Interface" }],
      code: { lang: "Embedded C — Compartment Check & Voice Trigger", snippet: `// MedVault - Medication Reminder\n#define COMPARTMENTS 6\nint irPins[COMPARTMENTS] = {13,12,14,27,26,25};\nbool doseTaken[COMPARTMENTS] = {false};\n\nDFRobotDFPlayerMini player;\n\nvoid playReminder(int compartment) {\n  player.play(compartment + 1);\n  delay(3000);\n}\n\nvoid checkCompartment(int idx) {\n  int val = digitalRead(irPins[idx]);\n  if (val == LOW && !doseTaken[idx]) {\n    doseTaken[idx] = true;\n    Firebase.setBool(firebaseData,\n      "/doses/comp" + String(idx), true);\n  }\n}\n\nvoid loop() {\n  for (int i = 0; i < COMPARTMENTS; i++) {\n    checkCompartment(i);\n  }\n  delay(5000);\n}` },
    },
    {
      id: "hawkeye", num: "03", year: "2024",
      name: "Hawkeye", sub: "Drone & Unmanned Vehicle Detection",
      desc: "Real-time drone detection using YOLOv5 and OpenCV with a live React + Streamlit dashboard for monitoring and alerts.",
      tags: ["YOLOv5", "OpenCV", "Python", "React", "Streamlit"],
      problem: "Unauthorized drones pose serious security risks to sensitive zones — airports, military perimeters, and public events. Hawkeye uses YOLOv5 real-time object detection to identify drones from live video feeds and serves detection data to a monitoring dashboard.",
      stats: [{ num: "YOLOv5", label: "Detection Model" }, { num: "Real-time", label: "Video Processing" }, { num: "Live", label: "Dashboard Feed" }, { num: "API", label: "Backend Integration" }],
      steps: [
        { num: "01", title: "Video Capture", desc: "OpenCV captures live video stream from camera feed or pre-recorded video sources frame by frame." },
        { num: "02", title: "YOLOv5 Inference", desc: "Each frame is passed through YOLOv5 which identifies drone objects and draws bounding boxes." },
        { num: "03", title: "API Dispatch", desc: "Python backend sends detection results (confidence, coordinates) to frontend via REST API." },
        { num: "04", title: "Live Dashboard", desc: "React and Streamlit display the annotated live feed with detection metadata and alert counters." },
      ],
      stack: [{ icon: "🤖", name: "YOLOv5", role: "Object Detection" }, { icon: "👁️", name: "OpenCV", role: "Frame Processing" }, { icon: "🐍", name: "Python", role: "Backend & Inference" }, { icon: "⚛️", name: "React", role: "Frontend Dashboard" }, { icon: "📊", name: "Streamlit", role: "Data Visualization" }, { icon: "🔗", name: "FastAPI", role: "REST API Layer" }],
      code: { lang: "Python — YOLOv5 Detection Loop", snippet: `import cv2, torch\n\nmodel = torch.hub.load('ultralytics/yolov5',\n                       'custom', path='weights.pt')\nmodel.conf = 0.45\n\ncap = cv2.VideoCapture(0)\n\nwhile cap.isOpened():\n    ret, frame = cap.read()\n    if not ret: break\n\n    results = model(frame)\n    detections = results.pandas().xyxy[0]\n\n    for _, row in detections.iterrows():\n        if row['name'] == 'drone':\n            x1,y1,x2,y2 = (int(row['xmin']),\n              int(row['ymin']),int(row['xmax']),\n              int(row['ymax']))\n            cv2.rectangle(frame,(x1,y1),(x2,y2),\n                          (0,100,255),2)\n            cv2.putText(frame,\n              f"DRONE {row['confidence']:.2f}",\n              (x1,y1-10),\n              cv2.FONT_HERSHEY_SIMPLEX,\n              0.6,(0,100,255),2)\n\ncap.release()` },
    },
    {
      id: "parkease", num: "04", year: "2023",
      name: "ParkEase", sub: "Smart Parking Management System",
      desc: "Mobile app for real-time parking slot visibility and booking. Won 1st Prize at SynTech-X 2024 Project Pitching Competition.",
      tags: ["Flutter", "Firebase", "Dart", "Mobile App", "Real-time DB"],
      problem: "Finding parking in busy urban areas wastes time and fuel. Drivers circle blocks with no real-time information. ParkEase gives drivers real-time visibility into slot availability and lets them reserve a spot before they arrive — reducing search time and improving utilization.",
      stats: [{ num: "Real-time", label: "Slot Availability" }, { num: "Mobile", label: "Flutter App" }, { num: "🏆", label: "1st Prize" }, { num: "Firebase", label: "Live Database" }],
      steps: [
        { num: "01", title: "Live Availability", desc: "Firebase Realtime Database streams live parking slot status updates directly to the app." },
        { num: "02", title: "Visual Slot Map", desc: "Users see an interactive map with color-coded slots — green (available), red (occupied)." },
        { num: "03", title: "Instant Booking", desc: "Users tap a slot to reserve it. The database updates instantly, preventing double-bookings." },
        { num: "04", title: "Booking Management", desc: "Users can view, modify, or cancel bookings. Admins manage slots from an admin panel." },
      ],
      stack: [{ icon: "📱", name: "Flutter", role: "Cross-platform Mobile" }, { icon: "🎯", name: "Dart", role: "Programming Language" }, { icon: "🔥", name: "Firebase RTDB", role: "Real-time Database" }, { icon: "🔐", name: "Firebase Auth", role: "Authentication" }, { icon: "🗺️", name: "Custom UI", role: "Slot Map Interface" }, { icon: "🏆", name: "SynTech-X 2024", role: "1st Prize Winner" }],
      code: { lang: "Dart / Flutter — Real-time Slot Listener", snippet: `final dbRef = FirebaseDatabase.instance.ref('slots');\n\nvoid initState() {\n  super.initState();\n  dbRef.onValue.listen((event) {\n    final data = Map<String,dynamic>.from(\n      event.snapshot.value as Map);\n    setState(() {\n      slots = data.entries.map((e) {\n        final val = Map<String,dynamic>\n          .from(e.value);\n        return ParkingSlot(\n          id: e.key,\n          isAvailable: val['available'] ?? true,\n        );\n      }).toList();\n    });\n  });\n}\n\nvoid bookSlot(String slotId, String userId) {\n  dbRef.child(slotId).update({\n    'available': false,\n    'bookedBy': userId,\n    'bookedAt': DateTime.now().toIso8601String(),\n  });\n}` },
    },
  ],
};

// ── Global CSS ────────────────────────────────────────────────────────────
const G = `
  @import url('https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=Share+Tech+Mono&family=Barlow:wght@300;400;500;600&display=swap');
  :root {
    --blue:#1a6bff; --blue-l:#4d8fff; --blue-d:#0d3d99;
    --blue-bg:#f0f5ff; --blue-bg2:#dceaff;
    --white:#ffffff; --bg:#f6f8fd; --bg2:#edf1fa;
    --txt:#0d1a2e; --txt2:#3a4a6b; --txt3:#6b7fa8;
    --border:#dce5f5; --border-h:#a8bef0;
  }
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
  html{scroll-behavior:smooth;}
  body{background:#fff;color:var(--txt);font-family:'Barlow',sans-serif;font-weight:300;overflow-x:hidden;}
  button{all:unset;} a{text-decoration:none;}
  ::placeholder{color:var(--txt3);opacity:.7;}
  @keyframes fadeUp{from{opacity:0;transform:translateY(22px)}to{opacity:1;transform:translateY(0)}}
  .fu {animation:fadeUp .5s ease both;}
  .fu1{animation:fadeUp .5s .07s ease both;}
  .fu2{animation:fadeUp .5s .14s ease both;}
  .fu3{animation:fadeUp .5s .21s ease both;}
  .fu4{animation:fadeUp .5s .28s ease both;}
  .fu5{animation:fadeUp .5s .35s ease both;}
`;

const c = {
  blue:"var(--blue)", blueL:"var(--blue-l)", blueD:"var(--blue-d)",
  blueBg:"var(--blue-bg)", blueBg2:"var(--blue-bg2)",
  white:"var(--white)", bg:"var(--bg)", bg2:"var(--bg2)",
  txt:"var(--txt)", txt2:"var(--txt2)", txt3:"var(--txt3)",
  border:"var(--border)", borderH:"var(--border-h)",
};

// ── Shared components ─────────────────────────────────────────────────────
const mono = { fontFamily:"'Share Tech Mono',monospace" };
const raj  = { fontFamily:"'Rajdhani',sans-serif" };

function Label({ children, style={} }) {
  return <span style={{ ...mono, fontSize:11, color:c.blue, letterSpacing:3, textTransform:"uppercase", ...style }}>{children}</span>;
}

function SecHead({ tag, title, light=false }) {
  return (
    <div style={{ marginBottom:52 }}>
      <Label style={{ display:"block", marginBottom:10, color: light?"rgba(255,255,255,.65)":c.blue }}>{tag}</Label>
      <h2 style={{ ...raj, fontSize:"clamp(28px,4vw,48px)", fontWeight:700, lineHeight:1, letterSpacing:-1, color: light?"#fff":c.txt }}>{title}</h2>
      <div style={{ width:44, height:3, background: light?"rgba(255,255,255,.45)":c.blue, marginTop:14, borderRadius:2 }} />
    </div>
  );
}

function Pill({ children }) {
  return <span style={{ ...mono, fontSize:10, padding:"4px 10px", background:c.blueBg, border:`1px solid ${c.border}`, color:c.blue, letterSpacing:1, borderRadius:3 }}>{children}</span>;
}

function HoverCard({ children, style={}, hoverBlue=false }) {
  const [hov, setHov] = useState(false);
  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        border:`1px solid ${hov ? c.blue : c.border}`,
        borderRadius:10,
        background: hov && hoverBlue ? c.blueBg : c.white,
        transition:"all .2s",
        transform: hov ? "translateY(-3px)" : "none",
        boxShadow: hov ? "0 8px 28px rgba(26,107,255,0.09)" : "none",
        ...style,
      }}>
      {children}
    </div>
  );
}

function CodeBlock({ lang, snippet }) {
  const [copied, setCopied] = useState(false);
  return (
    <div style={{ border:`1px solid ${c.border}`, borderRadius:8, overflow:"hidden" }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"10px 18px", background:c.blueBg2, borderBottom:`1px solid ${c.border}` }}>
        <Label style={{ color:c.blueD, letterSpacing:2 }}>{lang}</Label>
        <button onClick={() => { navigator.clipboard.writeText(snippet); setCopied(true); setTimeout(()=>setCopied(false),2000); }}
          style={{ ...mono, fontSize:11, padding:"4px 12px", border:`1px solid ${c.border}`, background:c.white, color: copied?c.blue:c.txt3, cursor:"pointer", borderRadius:4, transition:"all .2s" }}>
          {copied?"Copied!":"Copy"}
        </button>
      </div>
      <pre style={{ padding:"20px 18px", overflowX:"auto", background:"#f8faff" }}>
        <code style={{ ...mono, fontSize:12, color:c.txt2, lineHeight:1.8 }}>{snippet}</code>
      </pre>
    </div>
  );
}

// ── Nav ───────────────────────────────────────────────────────────────────
function Nav({ isHome, setPage }) {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);
  return (
    <nav style={{ position:"fixed", top:0, left:0, right:0, zIndex:100, display:"flex", justifyContent:"space-between", alignItems:"center", padding:"15px 60px", background: scrolled?"rgba(255,255,255,.97)":"rgba(255,255,255,.82)", backdropFilter:"blur(18px)", borderBottom:`1px solid ${scrolled?c.border:"transparent"}`, transition:"all .3s", boxShadow: scrolled?"0 2px 18px rgba(26,107,255,0.07)":"none" }}>
      <button onClick={() => { setPage("home"); window.scrollTo(0,0); }} style={{ ...raj, fontSize:22, fontWeight:700, color:c.blue, letterSpacing:3, cursor:"pointer" }}>AP</button>
      {isHome ? (
        <ul style={{ display:"flex", gap:28, listStyle:"none" }}>
          {["about","skills","projects","experience","achievements","contact"].map(l => (
            <li key={l}>
              <a href={`#${l}`} style={{ ...mono, fontSize:11, color:c.txt3, letterSpacing:2, textTransform:"uppercase", transition:"color .2s" }}
                onMouseEnter={e=>e.target.style.color=c.blue} onMouseLeave={e=>e.target.style.color=c.txt3}>{l}</a>
            </li>
          ))}
        </ul>
      ) : (
        <button onClick={() => { setPage("home"); window.scrollTo(0,0); }}
          style={{ ...mono, fontSize:11, color:c.txt3, letterSpacing:2, textTransform:"uppercase", cursor:"pointer", transition:"color .2s" }}
          onMouseEnter={e=>e.target.style.color=c.blue} onMouseLeave={e=>e.target.style.color=c.txt3}>← Back to Portfolio</button>
      )}
    </nav>
  );
}

// ── Hero ──────────────────────────────────────────────────────────────────
function Hero() {
  return (
    <section style={{ minHeight:"100vh", background:"linear-gradient(135deg,#1a6bff 0%,#0d3d99 100%)", display:"flex", alignItems:"center", padding:"120px 60px 80px", position:"relative", overflow:"hidden" }}>
      <div style={{ position:"absolute", inset:0, backgroundImage:"radial-gradient(rgba(255,255,255,.07) 1.5px,transparent 1.5px)", backgroundSize:"30px 30px", pointerEvents:"none" }} />
      <div style={{ position:"absolute", top:"-15%", right:"-5%", width:560, height:560, background:"radial-gradient(circle,rgba(255,255,255,.09) 0%,transparent 65%)", pointerEvents:"none" }} />
      <div style={{ position:"relative", zIndex:1 }}>
        <div className="fu" style={{ ...mono, fontSize:12, color:"rgba(255,255,255,.6)", letterSpacing:4, textTransform:"uppercase", marginBottom:22, display:"flex", alignItems:"center", gap:12 }}>
          <span style={{ display:"inline-block", width:34, height:1, background:"rgba(255,255,255,.35)" }} />
          {DATA.title}
        </div>
        <h1 className="fu1" style={{ ...raj, fontSize:"clamp(50px,8vw,106px)", fontWeight:700, lineHeight:.9, letterSpacing:-2, color:"#fff", marginBottom:10 }}>
          Amit<br /><span style={{ color:"rgba(255,255,255,.45)" }}>Panda</span>
        </h1>
        <div className="fu2" style={{ ...raj, fontSize:"clamp(15px,2vw,23px)", fontWeight:500, color:"rgba(255,255,255,.55)", letterSpacing:5, textTransform:"uppercase", marginBottom:30 }}>{DATA.tagline}</div>
        <p className="fu3" style={{ maxWidth:510, fontSize:16, lineHeight:1.8, color:"rgba(255,255,255,.73)", marginBottom:42 }}>{DATA.objective}</p>
        <div className="fu4" style={{ display:"flex", gap:13, flexWrap:"wrap" }}>
          <a href="#projects" style={{ ...mono, fontSize:12, letterSpacing:2, textTransform:"uppercase", padding:"13px 28px", background:"#fff", color:c.blue, borderRadius:4, transition:"all .2s", display:"inline-block" }}
            onMouseEnter={e=>e.currentTarget.style.background=c.blueBg} onMouseLeave={e=>e.currentTarget.style.background="#fff"}>
            View Projects
          </a>
          <a href="#contact" style={{ ...mono, fontSize:12, letterSpacing:2, textTransform:"uppercase", padding:"13px 28px", background:"transparent", color:"#fff", border:"1px solid rgba(255,255,255,.38)", borderRadius:4, transition:"all .2s" }}
            onMouseEnter={e=>{e.currentTarget.style.background="rgba(255,255,255,.1)";e.currentTarget.style.borderColor="rgba(255,255,255,.65)";}}
            onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.borderColor="rgba(255,255,255,.38)";}}>
            Get In Touch
          </a>
        </div>
      </div>
      <div className="fu5" style={{ position:"absolute", bottom:52, right:60, display:"flex", gap:50 }}>
        {DATA.stats.map(s => (
          <div key={s.num} style={{ textAlign:"center" }}>
