              <button style={{ display:"flex", alignItems:"center", gap:16, border:`1px solid ${hov?c.blue:c.border}`, borderRadius:10, padding:"20px 24px", background:hov?c.blueBg:c.white, cursor:"pointer", width:"100%", textAlign:"left", transition:"all .2s", color:"inherit" }}
