                </div>
              </button>
            );
          })()}
        </div>
        {/* Stack */}
        <div style={{ marginBottom:60 }}>
          <DHead tag="// Stack" title="Tech Stack" />
          <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:13 }}>
            {project.stack.map(s => {
              const [hov,setHov]=useState(false);
              return (
                <div key={s.name} style={{ border:`1px solid ${hov?c.blue:c.border}`, borderRadius:10, padding:"18px 14px", textAlign:"center", transition:"all .2s", background:hov?c.blueBg:c.white }}
