                  <div style={{ fontSize:22, marginBottom:7 }}>{s.icon}</div>
                  <div style={{ ...raj, fontSize:15, fontWeight:700, marginBottom:2, color:c.txt }}>{s.name}</div>
                  <div style={{ fontSize:12, color:c.txt3 }}>{s.role}</div>
                </div>
              );
            })}
          </div>
        </div>
        {/* Prev/Next */}
        <div style={{ display:"flex", justifyContent:"space-between", paddingTop:34, borderTop:`1px solid ${c.border}` }}>
          {[prev&&{label:`← ${prev.name}`,id:prev.id}, next&&{label:`${next.name} →`,id:next.id}].map((btn,i) => btn ? (
            <button key={btn.id} onClick={()=>{setPage(btn.id);window.scrollTo(0,0);}}
