              onMouseEnter={e=>{e.currentTarget.style.borderColor=c.blue;e.currentTarget.style.background=c.blueBg;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=c.border;e.currentTarget.style.background=c.white;}}>
              {btn.label}
            </button>
          ) : <div key={i} />)}
        </div>
      </div>
    </div>
  );
}

