  const project = DATA.projects.find(p => p.id === page);
  return (
    <>
      <style>{G}</style>
      <Nav isHome={page==="home"} setPage={setPage} />
      <div>
        {page === "home" ? (
          <><Hero /><About /><Skills /><Projects setPage={setPage} /><Experience /><Achievements /><Contact /><Footer /></>
        ) : project ? (
